parameters.functionCode:
try {
  const fs = require('fs');
  const leads = JSON.parse(fs.readFileSync('D:/Content OS/pc_data/leads.json','utf8') || '[]');
  const clients = JSON.parse(fs.readFileSync('D:/Content OS/pc_data/clients.json','utf8') || '[]');
  const fin = JSON.parse(fs.readFileSync('D:/Content OS/pc_data/finance.json','utf8') || '{"income":[]}');
  const income = fin.income.reduce((a,t) => a + (t.amount||0), 0);
  const newLeads = leads.filter(l => l.stage === 'new').length;
  const onCall = leads.filter(l => l.stage === 'call').length;
  return [{json: {
    total_leads: leads.length,
    new_leads: newLeads,
    on_call: onCall,
    clients: clients.length,
    income: income,
    kpi_pct: Math.round(income / 20000 * 100)
  }}];
} catch(e) {
  return [{json: {error: e.message}}];
}

